{
  "name": "PromptForge: Multi-Model AI Comparator",
  "description": "A high-fidelity tool to compare and refine prompts or text across simulated AI model personalities, including ChatGPT, Claude, Gemini, and more.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AIModelType {
  ChatGPT = 'ChatGPT',
  Claude = 'Claude',
  Gemini = 'Gemini',
  Copilot = 'Copilot',
  Grok = 'Grok',
  Perplexity = 'Perplexity'
}

export interface ModelResult {
  modelId: AIModelType;
  rewrittenText: string;
  refinementSuggestions: string[];
  metrics: {
    clarity: number;
    creativity: number;
    conciseness: number;
    professionalism: number;
  };
  explanation: string;
}

export interface ComparisonResponse {
  results: ModelResult[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { ComparisonResponse, AIModelType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `You are a meta-AI prompt engineering expert. 
Your task is to take a user's prompt or text and provide rewrites and refinements as if you were different top-tier AI models.

For each model, capture its unique 'personality':
- ChatGPT (GPT-4o): Balanced, logical, very structured, polite, and comprehensive.
- Claude (3.5 Sonnet): Nuanced, thoughtful, excellent prose, high emotional intelligence, and safety-conscious.
- Gemini (1.5 Pro): Creative, multi-modal focus, likes lists and broad context, integrated feel.
- Copilot: Task-oriented, professional, Microsoft-ecosystem aware, concise.
- Grok: Edgy, direct, less filtered, slightly witty or sharp.
- Perplexity: Fact-heavy, research-oriented, source-focused (even if simulated), extremely concise.

Provide a JSON response containing a rewrite and evaluation for EACH of these models based on the user's input.`;

export async function compareAIOutputs(input: string): Promise<ComparisonResponse> {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `User Input: "${input}"\n\nGenerate variations for all requested models.`,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          results: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                modelId: { type: Type.STRING, enum: Object.values(AIModelType) },
                rewrittenText: { type: Type.STRING },
                refinementSuggestions: { 
                  type: Type.ARRAY, 
                  items: { type: Type.STRING } 
                },
                metrics: {
                  type: Type.OBJECT,
                  properties: {
                    clarity: { type: Type.NUMBER },
                    creativity: { type: Type.NUMBER },
                    conciseness: { type: Type.NUMBER },
                    professionalism: { type: Type.NUMBER }
                  },
                  required: ["clarity", "creativity", "conciseness", "professionalism"]
                },
                explanation: { type: Type.STRING }
              },
              required: ["modelId", "rewrittenText", "refinementSuggestions", "metrics", "explanation"]
            }
          }
        },
        required: ["results"]
      }
    }
  });

  const text = response.text || '{}';
  return JSON.parse(text) as ComparisonResponse;
}

import React, { useState, useCallback } from 'react';
import { ComparisonResponse, ModelResult } from './types';
import { compareAIOutputs } from './services/geminiService';
import Header from './components/Header';
import PromptInput from './components/PromptInput';
import ComparisonGrid from './components/ComparisonGrid';
import AnalyticsView from './components/AnalyticsView';
import { Sparkles, BarChart3, LayoutGrid, Info } from 'lucide-react';

const App: React.FC = () => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState<ModelResult[]>([]);
  const [view, setView] = useState<'grid' | 'analytics'>('grid');
  const [error, setError] = useState<string | null>(null);

  const handleCompare = useCallback(async () => {
    if (!input.trim()) return;

    setLoading(true);
    setError(null);
    try {
      const data = await compareAIOutputs(input);
      setResults(data.results);
    } catch (err) {
      console.error(err);
      setError('Failed to fetch AI comparisons. Please try again.');
    } finally {
      setLoading(false);
    }
  }, [input]);

  return (
    <div className="flex flex-col min-h-screen">
      <Header />

      <main className="flex-grow container mx-auto px-4 py-8 max-w-7xl">
        <div className="grid grid-cols-1 gap-8">

          {/* Input Section */}
          <section className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
            <div className="flex items-center gap-2 mb-4 text-indigo-600 font-semibold">
              <Sparkles className="w-5 h-5" />
              <h2>Forge Your Prompt</h2>
            </div>
            <PromptInput 
              value={input} 
              onChange={setInput} 
              onRun={handleCompare} 
              isLoading={loading} 
            />
          </section>

          {error && (
            <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-xl flex items-center gap-2">
              <Info className="w-5 h-5" />
              {error}
            </div>
          )}

          {/* Results Section */}
          {(results.length > 0 || loading) && (
            <section>
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-4">
                  <h2 className="text-xl font-bold text-slate-800">Model Insights</h2>
                  <div className="flex bg-slate-200 p-1 rounded-lg">
                    <button 
                      onClick={() => setView('grid')}
                      className={`px-3 py-1.5 rounded-md flex items-center gap-2 text-sm font-medium transition-all ${view === 'grid' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-600 hover:text-slate-900'}`}
                    >
                      <LayoutGrid className="w-4 h-4" />
                      Grid
                    </button>
                    <button 
                      onClick={() => setView('analytics')}
                      className={`px-3 py-1.5 rounded-md flex items-center gap-2 text-sm font-medium transition-all ${view === 'analytics' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-600 hover:text-slate-900'}`}
                    >
                      <BarChart3 className="w-4 h-4" />
                      Analytics
                    </button>
                  </div>
                </div>
                {results.length > 0 && (
                   <span className="text-sm text-slate-500">Comparing {results.length} model variants</span>
                )}
              </div>

              {loading ? (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  {[1, 2, 3, 4, 5, 6].map((i) => (
                    <div key={i} className="bg-white rounded-xl border border-slate-200 p-6 h-64 animate-shimmer" />
                  ))}
                </div>
              ) : view === 'grid' ? (
                <ComparisonGrid results={results} />
              ) : (
                <AnalyticsView results={results} />
              )}
            </section>
          )}

          {results.length === 0 && !loading && (
            <div className="text-center py-20 opacity-40">
              <LayoutGrid className="w-16 h-16 mx-auto mb-4" />
              <p className="text-lg">Enter a prompt above to see magic across models</p>
            </div>
          )}
        </div>
      </main>

      <footer className="border-t border-slate-200 py-6 text-center text-sm text-slate-500">
        <p>&copy; 2024 PromptForge AI. Powered by Gemini 3 Pro Reasoning.</p>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import { Send, Loader2 } from 'lucide-react';

interface PromptInputProps {
  value: string;
  onChange: (val: string) => void;
  onRun: () => void;
  isLoading: boolean;
}

const PromptInput: React.FC<PromptInputProps> = ({ value, onChange, onRun, isLoading }) => {
  return (
    <div className="relative">
      <textarea
        value={value}
        onChange={(e) => onChange(e.target.value)}
        placeholder="Paste your text or prompt here to see how different AIs would rewrite or refine it..."
        className="w-full min-h-[160px] p-4 text-lg border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition-all resize-none bg-slate-50/50"
      />
      <div className="absolute bottom-4 right-4 flex items-center gap-3">
        <span className="text-xs text-slate-400 font-medium bg-white px-2 py-1 rounded border border-slate-100">
          {value.length} characters
        </span>
        <button
          onClick={onRun}
          disabled={isLoading || !value.trim()}
          className={`flex items-center gap-2 px-6 py-2.5 rounded-lg font-semibold shadow-md transition-all ${
            isLoading || !value.trim() 
            ? 'bg-slate-200 text-slate-400 cursor-not-allowed shadow-none' 
            : 'bg-indigo-600 text-white hover:bg-indigo-700 hover:scale-[1.02] active:scale-[0.98]'
          }`}
        >
          {isLoading ? (
            <>
              <Loader2 className="w-4 h-4 animate-spin" />
              Analyzing...
            </>
          ) : (
            <>
              <Send className="w-4 h-4" />
              Compare Models
            </>
          )}
        </button>
      </div>
    </div>
  );
};

export default PromptInput;

import React from 'react';
import { ModelResult, AIModelType } from '../types';
import { Copy, Check, MessageSquareCode, Lightbulb } from 'lucide-react';

const ModelIcons: Record<AIModelType, string> = {
  [AIModelType.ChatGPT]: '🟢',
  [AIModelType.Claude]: '🟠',
  [AIModelType.Gemini]: '🔵',
  [AIModelType.Copilot]: '💠',
  [AIModelType.Grok]: '⚫',
  [AIModelType.Perplexity]: '⚪',
};

const ComparisonGrid: React.FC<{ results: ModelResult[] }> = ({ results }) => {
  const [copiedId, setCopiedId] = React.useState<string | null>(null);

  const copyToClipboard = (text: string, id: string) => {
    navigator.clipboard.writeText(text);
    setCopiedId(id);
    setTimeout(() => setCopiedId(null), 2000);
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
      {results.map((res) => (
        <div key={res.modelId} className="bg-white rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-shadow overflow-hidden flex flex-col">
          <div className="p-4 border-b border-slate-100 bg-slate-50/30 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <span className="text-lg">{ModelIcons[res.modelId]}</span>
              <h3 className="font-bold text-slate-700">{res.modelId}</h3>
            </div>
            <button 
              onClick={() => copyToClipboard(res.rewrittenText, res.modelId)}
              className="p-1.5 hover:bg-slate-200 rounded-md transition-colors text-slate-500"
            >
              {copiedId === res.modelId ? <Check className="w-4 h-4 text-green-600" /> : <Copy className="w-4 h-4" />}
            </button>
          </div>

          <div className="p-5 flex-grow">
            <div className="text-sm text-slate-600 leading-relaxed mb-6 whitespace-pre-wrap italic">
              "{res.rewrittenText}"
            </div>

            <div className="space-y-4">
              <div>
                <div className="flex items-center gap-2 text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">
                  <Lightbulb className="w-3 h-3 text-amber-500" />
                  Refinement Suggestions
                </div>
                <ul className="space-y-1.5">
                  {res.refinementSuggestions.slice(0, 2).map((s, idx) => (
                    <li key={idx} className="text-xs text-slate-500 flex gap-2">
                      <span className="text-indigo-400">•</span>
                      {s}
                    </li>
                  ))}
                </ul>
              </div>

              <div>
                <div className="flex items-center gap-2 text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">
                  <MessageSquareCode className="w-3 h-3 text-indigo-500" />
                  Why it works
                </div>
                <p className="text-xs text-slate-500 italic">
                  {res.explanation}
                </p>
              </div>
            </div>
          </div>

          <div className="px-5 py-3 bg-slate-50 border-t border-slate-100 flex gap-4 text-[10px] font-bold text-slate-400">
            <div className="flex-1">
              <div className="mb-1 flex justify-between">
                <span>CLARITY</span>
                <span>{res.metrics.clarity * 10}/10</span>
              </div>
              <div className="h-1 bg-slate-200 rounded-full overflow-hidden">
                <div className="h-full bg-emerald-400" style={{ width: `${res.metrics.clarity * 100}%` }} />
              </div>
            </div>
            <div className="flex-1">
              <div className="mb-1 flex justify-between">
                <span>STYLE</span>
                <span>{res.metrics.creativity * 10}/10</span>
              </div>
              <div className="h-1 bg-slate-200 rounded-full overflow-hidden">
                <div className="h-full bg-indigo-400" style={{ width: `${res.metrics.creativity * 100}%` }} />
              </div>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
};

export default ComparisonGrid;

import React from 'react';
import { ModelResult } from '../types';
import { Radar, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, ResponsiveContainer, Legend, Tooltip, BarChart, Bar, XAxis, YAxis, CartesianGrid } from 'recharts';

const AnalyticsView: React.FC<{ results: ModelResult[] }> = ({ results }) => {
  const radarData = [
    { subject: 'Clarity', ...Object.fromEntries(results.map(r => [r.modelId, r.metrics.clarity])) },
    { subject: 'Creativity', ...Object.fromEntries(results.map(r => [r.modelId, r.metrics.creativity])) },
    { subject: 'Conciseness', ...Object.fromEntries(results.map(r => [r.modelId, r.metrics.conciseness])) },
    { subject: 'Professionalism', ...Object.fromEntries(results.map(r => [r.modelId, r.metrics.professionalism])) },
  ];

  const colors = ['#6366f1', '#ec4899', '#10b981', '#f59e0b', '#3b82f6', '#8b5cf6'];

  const barData = results.map(r => ({
    name: r.modelId,
    Score: (r.metrics.clarity + r.metrics.creativity + r.metrics.conciseness + r.metrics.professionalism) / 4
  }));

  return (
    <div className="space-y-8">
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

        {/* Radar Chart */}
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm h-[450px]">
          <h3 className="text-lg font-bold text-slate-800 mb-4">Metric Comparison</h3>
          <ResponsiveContainer width="100%" height="100%">
            <RadarChart cx="50%" cy="50%" outerRadius="80%" data={radarData}>
              <PolarGrid />
              <PolarAngleAxis dataKey="subject" />
              <PolarRadiusAxis angle={30} domain={[0, 1]} />
              {results.map((r, i) => (
                <Radar
                  key={r.modelId}
                  name={r.modelId}
                  dataKey={r.modelId}
                  stroke={colors[i % colors.length]}
                  fill={colors[i % colors.length]}
                  fillOpacity={0.2}
                />
              ))}
              <Legend />
              <Tooltip />
            </RadarChart>
          </ResponsiveContainer>
        </div>

        {/* Bar Chart Overall */}
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm h-[450px]">
          <h3 className="text-lg font-bold text-slate-800 mb-4">Overall Strength Score</h3>
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={barData}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} />
              <XAxis dataKey="name" />
              <YAxis domain={[0, 1]} />
              <Tooltip cursor={{ fill: '#f1f5f9' }} />
              <Bar 
                dataKey="Score" 
                fill="#6366f1" 
                radius={[4, 4, 0, 0]} 
                animationDuration={1500}
              />
            </BarChart>
          </ResponsiveContainer>
        </div>

      </div>

      <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm overflow-x-auto">
        <h3 className="text-lg font-bold text-slate-800 mb-4">Raw Comparison Table</h3>
        <table className="w-full text-left">
          <thead>
            <tr className="border-b border-slate-100 text-xs font-bold text-slate-400 uppercase">
              <th className="py-3 px-4">Model</th>
              <th className="py-3 px-4 text-center">Clarity</th>
              <th className="py-3 px-4 text-center">Creativity</th>
              <th className="py-3 px-4 text-center">Conciseness</th>
              <th className="py-3 px-4 text-center">Professionalism</th>
            </tr>
          </thead>
          <tbody className="text-sm">
            {results.map((r) => (
              <tr key={r.modelId} className="border-b border-slate-50 hover:bg-slate-50 transition-colors">
                <td className="py-3 px-4 font-bold text-slate-700">{r.modelId}</td>
                <td className="py-3 px-4 text-center">{(r.metrics.clarity * 100).toFixed(0)}%</td>
                <td className="py-3 px-4 text-center">{(r.metrics.creativity * 100).toFixed(0)}%</td>
                <td className="py-3 px-4 text-center">{(r.metrics.conciseness * 100).toFixed(0)}%</td>
                <td className="py-3 px-4 text-center">{(r.metrics.professionalism * 100).toFixed(0)}%</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AnalyticsView;

