import { GoogleGenAI, Type } from "@google/genai";
import { ComparisonResponse, AIModelType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `You are a meta-AI prompt engineering expert. 
Your task is to take a user's prompt or text and provide rewrites and refinements as if you were different top-tier AI models and specialized writing tools.

PART 1: Standard Tools
- ChatGPT: Balanced, structured.
- Claude: Thoughtful, high EQ.
- Gemini: Creative, context-rich.
- Jasper/Writesonic: Marketing/Conversion focused.
- Wordtune/QuillBot: Flow and precision.
- Pi: Conversational.

PART 2: Master Blends (CRITICAL)
For the "Master Blend" categories, you must synthesize the strengths of ALL tools (ChatGPT's logic, Claude's prose, Jasper's punchiness, and Pi's warmth) into a single optimized version for the specific platform:
- Discord Master Blend: Engaging, uses markdown/emojis, community-focused, conversational.
- Threads Master Blend: Hook-driven, concise, intellectual yet accessible, conversation-starter.
- Instagram Master Blend: Visual storytelling with words, short punchy captions, heavy on relevant hashtags, high energy.
- Facebook Master Blend: Relatable, story-driven, clear call-to-action, slightly longer/warmer.
- TikTok Master Blend: Script-based, fast-paced, includes hook/middle/bridge/CTA, informal/slang-aware.
- Blog Master Blend: SEO-friendly, structured with subheadings, authoritative yet readable.

