import { GoogleGenAI, Type } from "@google/genai";
import { ComparisonResponse, AIModelType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `You are a meta-AI prompt engineering expert. 
Your task is to take a user's prompt or text and provide rewrites and refinements as if you were different top-tier AI models and specialized writing tools.

Categorize each tool into one of: 'Core', 'Writing', 'Research', 'Social', 'Utility'.

PART 1: Tool DNA
- Core LLMs (ChatGPT, Claude, Gemini, Llama, DeepSeek, Grok): General-purpose, logical, broad knowledge.
- Writing (Jasper, Writesonic, Anyword, Wordtune, QuillBot, Lex, Notion AI): Marketing, flow, persuasion, collaborative.
- Research (Perplexity, NotebookLM, Gamma, Pitch, Poe, Scifocus, ScholarPen): Academic rigor, citation-heavy, slide-focused, data-rich.
- Utility (LanguageTool, Ginger, Copilot): Grammar-first, coding/task-oriented, safe.
- Social (Buffer AI, Pi): Engaging, short-form, friendly.

PART 2: Master Blends
For "Master Blend" categories (Discord, Threads, Instagram, Facebook, TikTok, Blog), synthesize strengths into the ultimate version for that platform.

Provide a JSON response containing a result for EVERY model/tool in the enum. Because this is a large list, ensure variety and accuracy in the categories.`;

export async function compareAIOutputs(input: string): Promise<ComparisonResponse> {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `User Input: "${input}"\n\nGenerate variations for ALL tools in the schema. Ensure each result includes a "category" property.`,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          results: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                modelId: { type: Type.STRING, enum: Object.values(AIModelType) },
                category: { type: Type.STRING, enum: ['Core', 'Writing', 'Research', 'Social', 'Utility'] },
                rewrittenText: { type: Type.STRING },
                refinementSuggestions: { 
                  type: Type.ARRAY, 
                  items: { type: Type.STRING } 
                },
                metrics: {
                  type: Type.OBJECT,
                  properties: {
                    clarity: { type: Type.NUMBER },
                    creativity: { type: Type.NUMBER },
                    conciseness: { type: Type.NUMBER },
                    professionalism: { type: Type.NUMBER }
                  },
                  required: ["clarity", "creativity", "conciseness", "professionalism"]
                },
                explanation: { type: Type.STRING },
                isMasterBlend: { type: Type.BOOLEAN }
              },
              required: ["modelId", "category", "rewrittenText", "refinementSuggestions", "metrics", "explanation"]
            }
          }
        },
        required: ["results"]
      }
    }
  });

  const text = response.text || '{}';
  const data = JSON.parse(text) as ComparisonResponse;

  data.results = data.results.map(r => ({
    ...r,
    isMasterBlend: r.modelId.toString().includes('Master Blend')
  }));

  return data;
}

export async function enhancePrompt(prompt: string): Promise<string> {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Rewrite this prompt to be more effective, clear, and structured for an AI. 
