import React, { useState, useCallback, useEffect } from 'react';
import { ComparisonResponse, ModelResult, AIModelType, HistoryEntry } from './types';
import { compareAIOutputs, refineUserPrompt } from './services/geminiService';
import Header from './components/Header';
import PromptInput from './components/PromptInput';
import ComparisonGrid from './components/ComparisonGrid';
import AnalyticsView from './components/AnalyticsView';
import HistoryPanel from './components/HistoryPanel';
import { Sparkles, BarChart3, LayoutGrid, Info } from 'lucide-react';

const HISTORY_KEY = 'promptforge_history';
const CUSTOM_MODELS_KEY = 'promptforge_custom_models';

const App: React.FC = () => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState<ModelResult[]>([]);
  const [view, setView] = useState<'grid' | 'analytics'>('grid');
  const [error, setError] = useState<string | null>(null);

  // Model Management State
  const [customModels, setCustomModels] = useState<string[]>([]);
  const [availableModels, setAvailableModels] = useState<string[]>([]);

  // History State
  const [history, setHistory] = useState<HistoryEntry[]>([]);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);

  // Initialize models and history
  useEffect(() => {
    const defaultModels = Object.values(AIModelType);
    const savedCustom = localStorage.getItem(CUSTOM_MODELS_KEY);
    let parsedCustom: string[] = [];
    if (savedCustom) {
      try { parsedCustom = JSON.parse(savedCustom); } catch (e) {}
    }
    setCustomModels(parsedCustom);
    setAvailableModels([...defaultModels, ...parsedCustom]);

    const savedHistory = localStorage.getItem(HISTORY_KEY);
    if (savedHistory) {
      try { setHistory(JSON.parse(savedHistory)); } catch (e) {}
    }
  }, []);

  // Sync history and custom models
  useEffect(() => {
    localStorage.setItem(HISTORY_KEY, JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    localStorage.setItem(CUSTOM_MODELS_KEY, JSON.stringify(customModels));
    setAvailableModels([...Object.values(AIModelType), ...customModels]);
  }, [customModels]);

  const handleCompare = useCallback(async (selectedModels: string[]) => {
    if (!input.trim() || selectedModels.length === 0) return;

    setLoading(true);
    setError(null);
    try {
      const data = await compareAIOutputs(input, selectedModels);
      setResults(data.results);

      const newEntry: HistoryEntry = {
        id: crypto.randomUUID(),
        timestamp: Date.now(),
        input: input,
        results: data.results
      };
      setHistory(prev => [newEntry, ...prev].slice(0, 50));
    } catch (err) {
      console.error(err);
      setError('Failed to fetch AI comparisons. Please try again.');
    } finally {
      setLoading(false);
    }
  }, [input]);

  const handleRefine = useCallback(async (modelId: string, rewrite: string) => {
    setError(null);
    try {
      const refined = await refineUserPrompt(input, rewrite, modelId);
      setInput(refined);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (err) {
      console.error(err);
      setError('Failed to refine prompt. Please try again.');
    }
  }, [input]);

  const handleAddCustomModel = (name: string) => {
    if (!availableModels.includes(name)) {
      setCustomModels(prev => [...prev, name]);
    }
  };

  const loadHistoryEntry = (entry: HistoryEntry) => {
    setInput(entry.input);
    setResults(entry.results);
    setIsHistoryOpen(false);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="flex flex-col min-h-screen">
      <Header onOpenHistory={() => setIsHistoryOpen(true)} />

      <HistoryPanel 
        isOpen={isHistoryOpen}
        onClose={() => setIsHistoryOpen(false)}
        history={history}
        onLoad={loadHistoryEntry}
        onDelete={(id) => setHistory(prev => prev.filter(e => e.id !== id))}
        onClearAll={() => confirm('Clear history?') && setHistory([])}
      />

      <main className="flex-grow container mx-auto px-4 py-8 max-w-7xl">
        <div className="grid grid-cols-1 gap-8">

          <section className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
            <div className="flex items-center gap-2 mb-4 text-indigo-600 font-semibold">
              <Sparkles className="w-5 h-5" />
              <h2>Forge Your Prompt</h2>
            </div>
            <PromptInput 
              value={input} 
              onChange={setInput} 
              onRun={handleCompare} 
              isLoading={loading}
              availableModels={availableModels}
              onAddCustomModel={handleAddCustomModel}
            />
          </section>

          {error && (
            <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-xl flex items-center gap-2">
              <Info className="w-5 h-5" />
              {error}
            </div>
          )}

          {(results.length > 0 || loading) && (
            <section>
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-4">
                  <h2 className="text-xl font-bold text-slate-800">Model Insights</h2>
                  <div className="flex bg-slate-200 p-1 rounded-lg">
                    <button 
                      onClick={() => setView('grid')}
                      className={`px-3 py-1.5 rounded-md flex items-center gap-2 text-sm font-medium transition-all ${view === 'grid' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-600 hover:text-slate-900'}`}
                    >
                      <LayoutGrid className="w-4 h-4" />
                      Grid
                    </button>
                    <button 
                      onClick={() => setView('analytics')}
                      className={`px-3 py-1.5 rounded-md flex items-center gap-2 text-sm font-medium transition-all ${view === 'analytics' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-600 hover:text-slate-900'}`}
                    >
                      <BarChart3 className="w-4 h-4" />
                      Analytics
                    </button>
                  </div>
                </div>
                {results.length > 0 && (
                   <span className="text-sm text-slate-500">Comparing {results.length} model variants</span>
                )}
              </div>

              {loading ? (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  {[1, 2, 3].map((i) => (
                    <div key={i} className="bg-white rounded-xl border border-slate-200 p-6 h-80 animate-shimmer" />
                  ))}
                </div>
              ) : view === 'grid' ? (
                <ComparisonGrid results={results} onRefine={handleRefine} />
              ) : (
                <AnalyticsView results={results} />
              )}
            </section>
          )}

          {results.length === 0 && !loading && (
            <div className="text-center py-20 opacity-40">
              <LayoutGrid className="w-16 h-16 mx-auto mb-4" />
              <p className="text-lg text-slate-500">Enter a prompt and select models to begin comparison</p>
            </div>
          )}
        </div>
      </main>

      <footer className="border-t border-slate-200 py-6 text-center text-sm text-slate-500">
        <p>&copy; 2024 PromptForge AI. Multi-model simulator and refiner.</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Send, Loader2, Wand2, ChevronDown, Check, Plus, Search } from 'lucide-react';
import { enhancePrompt } from '../services/geminiService';
import { AIModelType } from '../types';

interface PromptInputProps {
  value: string;
  onChange: (val: string) => void;
  onRun: (selectedModels: string[]) => void;
  isLoading: boolean;
  availableModels: string[];
  onAddCustomModel: (name: string) => void;
}

const PromptInput: React.FC<PromptInputProps> = ({ 
  value, 
  onChange, 
  onRun, 
  isLoading, 
  availableModels,
  onAddCustomModel
}) => {
  const [isRefining, setIsRefining] = useState(false);
  const [isSelectorOpen, setIsSelectorOpen] = useState(false);
  const [selectedModels, setSelectedModels] = useState<Set<string>>(new Set(['ChatGPT', 'Claude', 'Gemini', 'Perplexity']));
  const [searchTerm, setSearchTerm] = useState('');
  const [customModelName, setCustomModelName] = useState('');
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsSelectorOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleRefine = async () => {
    if (!value.trim()) return;
    setIsRefining(true);
    try {
      const refined = await enhancePrompt(value);
      onChange(refined);
    } catch (err) {
      console.error(err);
    } finally {
      setIsRefining(false);
    }
  };

  const toggleModel = (model: string) => {
    const next = new Set(selectedModels);
    if (next.has(model)) next.delete(model);
    else next.add(model);
    setSelectedModels(next);
  };

  const filteredModels = availableModels.filter(m => 
    m.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const isAllFilteredSelected = filteredModels.length > 0 && filteredModels.every(m => selectedModels.has(m));

  const handleSelectAll = () => {
    const next = new Set(selectedModels);
    if (isAllFilteredSelected) {
      filteredModels.forEach(m => next.delete(m));
    } else {
      filteredModels.forEach(m => next.add(m));
    }
    setSelectedModels(next);
  };

  const handleAddCustom = () => {
    if (customModelName.trim()) {
      onAddCustomModel(customModelName.trim());
      setSelectedModels(prev => new Set(prev).add(customModelName.trim()));
      setCustomModelName('');
    }
  };

  return (
    <div className="space-y-4">
      {/* Selection Control Bar */}
      <div className="flex flex-wrap items-center gap-2 mb-2">
        <div className="relative" ref={dropdownRef}>
          <button
            onClick={() => setIsSelectorOpen(!isSelectorOpen)}
            className="flex items-center gap-2 px-3 py-1.5 rounded-lg border border-slate-200 bg-white hover:bg-slate-50 transition-all text-xs font-bold text-slate-600 shadow-sm"
          >
            Select Models ({selectedModels.size})
            <ChevronDown className={`w-3.5 h-3.5 transition-transform ${isSelectorOpen ? 'rotate-180' : ''}`} />
          </button>

          {isSelectorOpen && (
            <div className="absolute top-full left-0 mt-2 w-64 bg-white border border-slate-200 rounded-xl shadow-xl z-[60] overflow-hidden flex flex-col max-h-80 animate-in fade-in zoom-in duration-150">
              <div className="p-3 border-b border-slate-100 bg-slate-50 flex items-center gap-2">
                <Search className="w-4 h-4 text-slate-400" />
                <input 
                  type="text" 
                  placeholder="Search models..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="bg-transparent text-sm w-full outline-none text-slate-700"
                />
              </div>

              {/* Select All Toggle */}
              <div className="px-3 py-2 border-b border-slate-100 flex items-center justify-between bg-white">
                <button 
                  onClick={handleSelectAll}
                  className="text-[10px] font-bold text-indigo-600 hover:text-indigo-700 uppercase tracking-wider transition-colors"
                >
                  {isAllFilteredSelected ? 'Deselect All' : 'Select All'}
                </button>
                <span className="text-[10px] text-slate-400 font-bold uppercase">
                  {filteredModels.length} Models
                </span>
              </div>

              <div className="flex-grow overflow-y-auto p-1 custom-scrollbar">
                {filteredModels.length > 0 ? (
                  filteredModels.map((model) => (
                    <button
                      key={model}
                      onClick={() => toggleModel(model)}
                      className="w-full flex items-center justify-between px-3 py-2 rounded-md hover:bg-slate-50 transition-colors text-sm font-medium text-slate-700"
                    >
                      {model}
                      {selectedModels.has(model) && <Check className="w-4 h-4 text-indigo-600" />}
                    </button>
                  ))
                ) : (
                  <div className="p-4 text-center text-xs text-slate-400">
                    No models found
                  </div>
                )}
              </div>
              <div className="p-2 border-t border-slate-100 bg-slate-50 flex items-center gap-1">
                <input 
                  type="text" 
                  placeholder="Add custom model..."
                  value={customModelName}
                  onChange={(e) => setCustomModelName(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleAddCustom()}
                  className="bg-white border border-slate-200 rounded-md px-2 py-1.5 text-xs w-full outline-none focus:ring-1 focus:ring-indigo-500"
                />
                <button 
                  onClick={handleAddCustom}
                  className="p-1.5 bg-indigo-600 text-white rounded-md hover:bg-indigo-700 transition-colors"
                >
                  <Plus className="w-4 h-4" />
                </button>
              </div>
            </div>
          )}
        </div>

        <div className="flex flex-wrap gap-1">
          {Array.from(selectedModels).slice(0, 5).map(m => (
            <span key={m} className="px-2 py-0.5 bg-indigo-50 text-indigo-600 text-[10px] font-bold rounded-full border border-indigo-100">
              {m}
            </span>
          ))}
          {selectedModels.size > 5 && (
            <span className="px-2 py-0.5 bg-slate-100 text-slate-500 text-[10px] font-bold rounded-full">
              +{selectedModels.size - 5} more
            </span>
          )}
        </div>
      </div>

      <div className="relative">
        <textarea
          value={value}
          onChange={(e) => onChange(e.target.value)}
          placeholder="Paste your text or prompt here..."
          className="w-full min-h-[160px] p-4 text-lg border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition-all resize-none bg-slate-50/50"
        />
        <div className="absolute bottom-4 right-4 flex items-center gap-3">
          <button
            onClick={handleRefine}
            disabled={isLoading || isRefining || !value.trim()}
            className={`flex items-center gap-2 px-4 py-2.5 rounded-lg font-semibold border transition-all ${
              isLoading || isRefining || !value.trim()
              ? 'border-slate-100 text-slate-300 cursor-not-allowed'
              : 'border-indigo-200 text-indigo-600 bg-white hover:bg-indigo-50 hover:border-indigo-300'
            }`}
          >
            {isRefining ? <Loader2 className="w-4 h-4 animate-spin" /> : <Wand2 className="w-4 h-4" />}
            <span className="hidden md:inline">Refine</span>
          </button>

          <button
            onClick={() => onRun(Array.from(selectedModels))}
            disabled={isLoading || isRefining || !value.trim() || selectedModels.size === 0}
            className={`flex items-center gap-2 px-6 py-2.5 rounded-lg font-semibold shadow-md transition-all ${
              isLoading || isRefining || !value.trim() || selectedModels.size === 0
              ? 'bg-slate-200 text-slate-400 cursor-not-allowed shadow-none' 
              : 'bg-indigo-600 text-white hover:bg-indigo-700 hover:scale-[1.02] active:scale-[0.98]'
            }`}
          >
            {isLoading ? (
              <>
                <Loader2 className="w-4 h-4 animate-spin" />
                Processing...
              </>
            ) : (
              <>
                <Send className="w-4 h-4" />
                Compare Models
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

export default PromptInput;

import { GoogleGenAI, Type } from "@google/genai";
import { ComparisonResponse, AIModelType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `You are a meta-AI prompt engineering expert and persona simulator. 
Your task is to take a user's prompt or text and provide:
1. A REWRITE: An optimized version of their prompt tailored to a specific model's personality.
2. AN ANSWER: A direct, chat-like response to the original prompt, simulating how that specific AI would answer it.

FORMATTING RULES FOR ANSWERS:
- Use bullet points for the response (e.g., using '•' or '-').
- DO NOT use markdown bolding (avoid '**').
- Keep the language natural to the persona but strictly follow the "No Bold" rule.

Categorize each tool into one of: 'Core', 'Writing', 'Research', 'Social', 'Utility'.

PART 1: Tool DNA
- Core LLMs: Logical, broad knowledge.
- Writing: Marketing, flow, persuasion.
- Research: Academic rigor, data-rich.
- Utility: Grammar-first, coding/task-oriented.
- Social: Engaging, short-form, friendly.

PART 2: Custom Tools
If a model name is provided that isn't in your standard list, infer its "personality" based on its name and provide a distinct rewrite and answer.

Provide a JSON response containing a result for EVERY requested model.`;

export async function compareAIOutputs(input: string, modelsToRun: string[]): Promise<ComparisonResponse> {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `User Input: "${input}"\n\nONLY generate variations for these SPECIFIC models: ${modelsToRun.join(', ')}. 
    For each, provide a "rewrittenText" (the better prompt) AND an "answerText" (the simulated response formatted as simple bullets without any bold markdown).`,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          results: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                modelId: { type: Type.STRING },
                category: { type: Type.STRING, enum: ['Core', 'Writing', 'Research', 'Social', 'Utility'] },
                rewrittenText: { type: Type.STRING },
                answerText: { type: Type.STRING },
                refinementSuggestions: { 
                  type: Type.ARRAY, 
                  items: { type: Type.STRING } 
                },
                metrics: {
                  type: Type.OBJECT,
                  properties: {
                    clarity: { type: Type.NUMBER },
                    creativity: { type: Type.NUMBER },
                    conciseness: { type: Type.NUMBER },
                    professionalism: { type: Type.NUMBER }
                  },
                  required: ["clarity", "creativity", "conciseness", "professionalism"]
                },
                explanation: { type: Type.STRING }
              },
              required: ["modelId", "category", "rewrittenText", "answerText", "refinementSuggestions", "metrics", "explanation"]
            }
          }
        },
        required: ["results"]
      }
    }
  });

  const text = response.text || '{"results": []}';
  const data = JSON.parse(text) as ComparisonResponse;

  data.results = data.results.map(r => ({
    ...r,
    isMasterBlend: r.modelId.toString().includes('Master Blend')
  }));

  return data;
}

export async function enhancePrompt(prompt: string): Promise<string> {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Rewrite this prompt to be more effective, clear, and structured for an AI. 
    Maintain the original intent but add necessary context, constraints, and instructions to get better results.

    User Input: "${prompt}"

    Output ONLY the improved prompt text.`,
    config: {
      systemInstruction: "You are a professional Prompt Engineer. Your goal is to turn lazy, short prompts into high-performance, structured instructions.",
    }
  });

  return response.text?.trim() || prompt;
}

export async function refineUserPrompt(originalPrompt: string, rewrite: string, modelId: string): Promise<string> {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `The user originally wrote: "${originalPrompt}"

A simulated ${modelId} rewrite of this was: "${rewrite}"

Your task is to create a NEW, highly optimized PROMPT that the user should use to get this level of quality or better from an AI. 
This "Refined Prompt" should include clear instructions, persona, context, and formatting rules that help an LLM understand exactly what to do.

Output ONLY the new prompt text. Do not include any preamble like "Here is your prompt:".`,
    config: {
      systemInstruction: "You are an expert Prompt Engineer. You transform simple ideas into structured, high-performance instructions for AI models.",
    }
  });

  return response.text?.trim() || originalPrompt;
}

