import { GoogleGenAI, Type } from "@google/genai";
import { ComparisonResponse, ModelResult, AIModelType } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `You are a meta-AI prompt engineering expert and persona simulator. 
Your task is to take a user's prompt or text and provide:
1. A REWRITE: An optimized version of their prompt tailored to a specific model's personality.
2. AN ANSWER: A direct, chat-like response to the original prompt, simulating how that specific AI would answer it.

FORMATTING RULES FOR ANSWERS:
- Use bullet points for the response (e.g., using '•' or '-').
- DO NOT use markdown bolding (avoid '**').
- Keep the language natural to the persona but strictly follow the "No Bold" rule.

Categorize the tool into one of: 'Core', 'Writing', 'Research', 'Social', 'Utility'.

PART 1: Tool DNA
- Core LLMs: Logical, broad knowledge.
- Writing: Marketing, flow, persuasion.
- Research: Academic rigor, data-rich.
- Utility: Grammar-first, coding/task-oriented.
- Social: Engaging, short-form, friendly.

PART 2: Custom Tools
If a model name is provided that isn't in your standard list, infer its "personality" based on its name and provide a distinct rewrite and answer.`;

/**
 * Generates a single model result. 
 * This allows for parallel calls and incremental UI updates.
 */
export async function generateSingleModelOutput(input: string, modelId: string): Promise<ModelResult> {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview', // Using flash for individual speed
    contents: `User Input: "${input}"\n\nGenerate a variation specifically for: ${modelId}. 
    Provide a "rewrittenText" (the better prompt) AND an "answerText" (the simulated response formatted as simple bullets without any bold markdown).`,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          modelId: { type: Type.STRING },
          category: { type: Type.STRING, enum: ['Core', 'Writing', 'Research', 'Social', 'Utility'] },
          rewrittenText: { type: Type.STRING },
          answerText: { type: Type.STRING },
          refinementSuggestions: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING } 
          },
          metrics: {
            type: Type.OBJECT,
            properties: {
              clarity: { type: Type.NUMBER },
              creativity: { type: Type.NUMBER },
              conciseness: { type: Type.NUMBER },
              professionalism: { type: Type.NUMBER }
            },
            required: ["clarity", "creativity", "conciseness", "professionalism"]
          },
          explanation: { type: Type.STRING }
        },
        required: ["modelId", "category", "rewrittenText", "answerText", "refinementSuggestions", "metrics", "explanation"]
      }
    }
  });

  const text = response.text || '{}';
  const result = JSON.parse(text) as ModelResult;

  return {
    ...result,
    modelId, // Ensure it matches what was requested
    isMasterBlend: modelId.toString().includes('Master Blend')
  };
}

export async function enhancePrompt(prompt: string): Promise<string> {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Rewrite this prompt to be more effective, clear, and structured for an AI. 
    Maintain the original intent but add necessary context, constraints, and instructions to get better results.

    User Input: "${prompt}"

    Output ONLY the improved prompt text.`,
    config: {
      systemInstruction: "You are a professional Prompt Engineer. Your goal is to turn lazy, short prompts into high-performance, structured instructions.",
    }
  });

  return response.text?.trim() || prompt;
}

export async function refineUserPrompt(originalPrompt: string, rewrite: string, modelId: string): Promise<string> {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `The user originally wrote: "${originalPrompt}"

A simulated ${modelId} rewrite of this was: "${rewrite}"

Your task is to create a NEW, highly optimized PROMPT that the user should use to get this level of quality or better from an AI. 
This "Refined Prompt" should include clear instructions, persona, context, and formatting rules that help an LLM understand exactly what to do.

Output ONLY the new prompt text. Do not include any preamble like "Here is your prompt:".`,
    config: {
      systemInstruction: "You are an expert Prompt Engineer. You transform simple ideas into structured, high-performance instructions for AI models.",
    }
  });

  return response.text?.trim() || originalPrompt;
}

import React, { useState, useCallback, useEffect } from 'react';
import { ComparisonResponse, ModelResult, AIModelType, HistoryEntry } from './types';
import { generateSingleModelOutput, refineUserPrompt } from './services/geminiService';
import Header from './components/Header';
import PromptInput from './components/PromptInput';
import ComparisonGrid from './components/ComparisonGrid';
import AnalyticsView from './components/AnalyticsView';
import HistoryPanel from './components/HistoryPanel';
import { Sparkles, BarChart3, LayoutGrid, Info } from 'lucide-react';

const HISTORY_KEY = 'promptforge_history';
const CUSTOM_MODELS_KEY = 'promptforge_custom_models';

const App: React.FC = () => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState<ModelResult[]>([]);
  const [pendingModels, setPendingModels] = useState<string[]>([]);
  const [view, setView] = useState<'grid' | 'analytics'>('grid');
  const [error, setError] = useState<string | null>(null);

  // Model Management State
  const [customModels, setCustomModels] = useState<string[]>([]);
  const [availableModels, setAvailableModels] = useState<string[]>([]);

  // History State
  const [history, setHistory] = useState<HistoryEntry[]>([]);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);

  // Initialize models and history
  useEffect(() => {
    const defaultModels = Object.values(AIModelType);
    const savedCustom = localStorage.getItem(CUSTOM_MODELS_KEY);
    let parsedCustom: string[] = [];
    if (savedCustom) {
      try { parsedCustom = JSON.parse(savedCustom); } catch (e) {}
    }
    setCustomModels(parsedCustom);
    setAvailableModels([...defaultModels, ...parsedCustom]);

    const savedHistory = localStorage.getItem(HISTORY_KEY);
    if (savedHistory) {
      try { setHistory(JSON.parse(savedHistory)); } catch (e) {}
    }
  }, []);

  // Sync history and custom models
  useEffect(() => {
    if (results.length > 0 && !loading && pendingModels.length === 0) {
      localStorage.setItem(HISTORY_KEY, JSON.stringify(history));
    }
  }, [history, results, loading, pendingModels]);

  useEffect(() => {
    localStorage.setItem(CUSTOM_MODELS_KEY, JSON.stringify(customModels));
    setAvailableModels([...Object.values(AIModelType), ...customModels]);
  }, [customModels]);

  const handleCompare = useCallback(async (selectedModels: string[]) => {
    if (!input.trim() || selectedModels.length === 0) return;

    setLoading(true);
    setError(null);
    setResults([]);
    setPendingModels(selectedModels);

    const currentResults: ModelResult[] = [];

    // Trigger all requests in parallel
    const promises = selectedModels.map(async (modelId) => {
      try {
        const result = await generateSingleModelOutput(input, modelId);
        setResults(prev => [...prev, result]);
        currentResults.push(result);
      } catch (err) {
        console.error(`Error generating for ${modelId}:`, err);
        // We could add a "failed" state to results here
      } finally {
        setPendingModels(prev => prev.filter(m => m !== modelId));
      }
    });

    // Wait for all to finish for history purposes
    await Promise.all(promises);

    if (currentResults.length > 0) {
      const newEntry: HistoryEntry = {
        id: crypto.randomUUID(),
        timestamp: Date.now(),
        input: input,
        results: currentResults
      };
      setHistory(prev => [newEntry, ...prev].slice(0, 50));
    }

    setLoading(false);
  }, [input]);

  const handleRefine = useCallback(async (modelId: string, rewrite: string) => {
    setError(null);
    try {
      const refined = await refineUserPrompt(input, rewrite, modelId);
      setInput(refined);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (err) {
      console.error(err);
      setError('Failed to refine prompt. Please try again.');
    }
  }, [input]);

  const handleAddCustomModel = (name: string) => {
    if (!availableModels.includes(name)) {
      setCustomModels(prev => [...prev, name]);
    }
  };

  const loadHistoryEntry = (entry: HistoryEntry) => {
    setInput(entry.input);
    setResults(entry.results);
    setPendingModels([]);
    setIsHistoryOpen(false);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <div className="flex flex-col min-h-screen">
      <Header onOpenHistory={() => setIsHistoryOpen(true)} />

      <HistoryPanel 
        isOpen={isHistoryOpen}
        onClose={() => setIsHistoryOpen(false)}
        history={history}
        onLoad={loadHistoryEntry}
        onDelete={(id) => setHistory(prev => prev.filter(e => e.id !== id))}
        onClearAll={() => confirm('Clear history?') && setHistory([])}
      />

      <main className="flex-grow container mx-auto px-4 py-8 max-w-7xl">
        <div className="grid grid-cols-1 gap-8">

          <section className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
            <div className="flex items-center gap-2 mb-4 text-indigo-600 font-semibold">
              <Sparkles className="w-5 h-5" />
              <h2>Forge Your Prompt</h2>
            </div>
            <PromptInput 
              value={input} 
              onChange={setInput} 
              onRun={handleCompare} 
              isLoading={loading}
              availableModels={availableModels}
              onAddCustomModel={handleAddCustomModel}
            />
          </section>

          {error && (
            <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-xl flex items-center gap-2">
              <Info className="w-5 h-5" />
              {error}
            </div>
          )}

          {(results.length > 0 || pendingModels.length > 0) && (
            <section>
              <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-4">
                  <h2 className="text-xl font-bold text-slate-800">Model Insights</h2>
                  <div className="flex bg-slate-200 p-1 rounded-lg">
                    <button 
                      onClick={() => setView('grid')}
                      className={`px-3 py-1.5 rounded-md flex items-center gap-2 text-sm font-medium transition-all ${view === 'grid' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-600 hover:text-slate-900'}`}
                    >
                      <LayoutGrid className="w-4 h-4" />
                      Grid
                    </button>
                    <button 
                      onClick={() => setView('analytics')}
                      className={`px-3 py-1.5 rounded-md flex items-center gap-2 text-sm font-medium transition-all ${view === 'analytics' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-600 hover:text-slate-900'}`}
                    >
                      <BarChart3 className="w-4 h-4" />
                      Analytics
                    </button>
                  </div>
                </div>
                <div className="flex items-center gap-3">
                   {pendingModels.length > 0 && (
                     <div className="flex items-center gap-2 bg-indigo-50 text-indigo-600 px-3 py-1 rounded-full text-xs font-bold animate-pulse">
                        <div className="w-2 h-2 bg-indigo-600 rounded-full animate-bounce" />
                        {pendingModels.length} models processing...
                     </div>
                   )}
                   <span className="text-sm text-slate-500">{results.length} ready</span>
                </div>
              </div>

              {view === 'grid' ? (
                <ComparisonGrid results={results} pendingModels={pendingModels} onRefine={handleRefine} />
              ) : (
                <AnalyticsView results={results} />
              )}
            </section>
          )}

          {results.length === 0 && pendingModels.length === 0 && !loading && (
            <div className="text-center py-20 opacity-40">
              <LayoutGrid className="w-16 h-16 mx-auto mb-4" />
              <p className="text-lg text-slate-500">Enter a prompt and select models to begin comparison</p>
            </div>
          )}
        </div>
      </main>

      <footer className="border-t border-slate-200 py-6 text-center text-sm text-slate-500">
        <p>&copy; 2024 PromptForge AI. Multi-model simulator and refiner.</p>
      </footer>
    </div>
  );
};

export default App;

